import { Component, h, Prop, State } from '@stencil/core';
import { defaultQuestionSet } from '../../subcomponents/constants';
import { FetchStatus, QuizOption } from '../../subcomponents/types';
import { InitialCard } from '../../subcomponents/quiz/InitialCard';
import { ResultCard } from '../../subcomponents/quiz/ResultCard';
import { QnACard } from '../../subcomponents/quiz/QnACard';

@Component({
  tag: 'sleep-apnea-quiz',
  styleUrl: 'sleep-apnea-quiz.css',
  shadow: true,
})
export class QuizCardComponent {
  @Prop() qnaset: any;
  @Prop() test: string;
  @Prop() quiztitle: string = 'How much do you know about sleep apnea?';
  @Prop() quizdescription: string = 'Take this quick quiz to learn more about sleep apnea and feel empowered to talk to a provider if you are experiencing symptoms.';
  @Prop() url: string;

  @State() isInitial: boolean = true;
  @State() isClicked: boolean = false;
  @State() capturedAnswer: boolean = false;
  @State() capturedIndex: number = 0;
  @State() isAnswerRevealed: boolean = false;
  @State() isQuizCompleted: boolean = false;
  @State() score: number = 0;
  @State() answeredQuestions: Set<number> = new Set();
  @State() revealedQuestions: Set<number> = new Set();
  @State() viewAnswers: boolean = false;
  @State() wrongAttempts: number = 0;
  // New state to track per-question state
  @State() questionStates: Map<number, { isClicked: boolean; capturedAnswer: boolean; capturedIndex: number; wrongAttempts: number }> = new Map();
  @State() timeodOutReveal: boolean = false;
  @State() fetchStatus: FetchStatus = { isLoading: false, error: false };
  @State() isMobile: boolean = typeof window !== 'undefined' ? window.innerWidth <= 991 : false;

  private totalSets: number = 0;
  private currentSet: number = 0;
  private correctAnsTimeout: any;
  private incorrectAnsTimeout: any;

  componentWillLoad() {
    this.qnaset = this.qnaset || defaultQuestionSet;
    this.totalSets = this.qnaset.length;
    this.viewAnswers = false;
    this.questionStates = new Map();
  }

  componentDidLoad() {
    window.addEventListener('resize', this.handleResize);
  }

  disconnectedCallback() {
    window.removeEventListener('resize', this.handleResize);
  }

  private handleResize = () => {
    this.isMobile = window.innerWidth <= 991;
  };

  getQuizData = () => {
    const { data } = defaultQuestionSet;
    this.qnaset = data;
    this.totalSets = data.length;
    this.isInitial = false;
   
  };

  handleOptionClick = (option: QuizOption, index: number) => {
    this.capturedAnswer = option.isCorrect;
    this.isClicked = true;
    this.capturedIndex = index;

    // Get current state or create new one
    const currentState = this.questionStates.get(this.currentSet) || {
      isClicked: false,
      capturedAnswer: false,
      capturedIndex: 0,
      wrongAttempts: 0,
    };

    if (!option.isCorrect) {
      // Update wrong attempts
      const newWrongAttempts = option.totalOptions === 2 ? option.totalOptions : currentState.wrongAttempts + 1;

      this.wrongAttempts = newWrongAttempts;

      // Save updated wrong attempts to question state
      this.questionStates.set(this.currentSet, {
        ...currentState,
        isClicked: true,
        capturedIndex: index,
        wrongAttempts: newWrongAttempts,
      });

      if (newWrongAttempts >= 2) {
        this.incorrectAnsTimeout = setTimeout(() => {
          this.handleRevealAnswer();
        }, 1000);
      }
    } else {
      // Answer is correct
      this.questionStates.set(this.currentSet, {
        ...currentState,
        isClicked: true,
        capturedAnswer: true,
        capturedIndex: index,
      });
    }

    // Allowing re-attempt after wrong answer
    if (this.isAnswerRevealed && option.isCorrect && !this.answeredQuestions.has(this.currentSet)) {
      this.score++;
      this.answeredQuestions.add(this.currentSet);
    } else if (!this.answeredQuestions.has(this.currentSet)) {
      // If not answered yet
      if (option.isCorrect) {
        this.correctAnsTimeout = setTimeout(() => {
          this.timeodOutReveal = true;
        }, 1000);
        this.score++;
        this.answeredQuestions.add(this.currentSet);
      }
    }
  };
  handleRevealAnswer = () => {
    this.capturedAnswer = true;
    this.isAnswerRevealed = true;
    this.timeodOutReveal = true;
    this.revealedQuestions.add(this.currentSet);

    const currentState = this.questionStates.get(this.currentSet) || {
      isClicked: true,
      capturedAnswer: true,
      capturedIndex: 0,
      wrongAttempts: 2,
    };

    this.questionStates.set(this.currentSet, {
      ...currentState,
      isClicked: true,
      capturedAnswer: true,
    });
  };

  // Helper to set state for answered or revealed question
  private setAnsweredStateForCurrent() {
    this.isClicked = true;
    this.isAnswerRevealed = true;
    this.capturedAnswer = true;
    this.timeodOutReveal = true;
    const question = this.qnaset[this.currentSet];
    const options = Object.entries(question).filter(([key]) => key.startsWith('option'));
    const correctIdx = options.findIndex(([key]) => key === question.correct_answer);
    this.capturedIndex = correctIdx !== -1 ? correctIdx : 0;
  }

  handleProceedToPreviousQuestion = () => {
    if (this.currentSet > 0) {
      this.currentSet--;
      if (this.viewAnswers) {
        this.setViewAnswersState(this.currentSet);
      } else if (this.answeredQuestions.has(this.currentSet) || this.revealedQuestions.has(this.currentSet)) {
        this.setAnsweredStateForCurrent();
      } else {
        const savedState = this.questionStates.get(this.currentSet);
        if (savedState) {
          this.isClicked = savedState.isClicked;
          this.capturedAnswer = savedState.capturedAnswer;
          this.capturedIndex = savedState.capturedIndex;
          this.wrongAttempts = savedState.wrongAttempts;
          this.timeodOutReveal = false;
          this.isAnswerRevealed = false;
        } else {
          this.resetQuizState();
        }
      }
      this.qnaset = [...this.qnaset];
    } else if (this.currentSet === 0) {
      this.isInitial = true;
    }
  };

  handleProceedQuiz = () => {
    this.handleProceedToPreviousQuestion();
  };

  //  reveals entire answer set on click of view all answers
  private setViewAnswersState(questionIndex: number) {
    this.isClicked = true;
    this.isAnswerRevealed = true;
    this.capturedAnswer = true;

    // const options = Object.entries(question).filter(([key]) => key.startsWith('option'));
    // this.capturedIndex = options.findIndex(([key]) => isCorrectAns(key, correctAnswerKey));

    this.currentSet = questionIndex;
  }

  // reset quiz
  private resetQuizState() {
    this.isClicked = false;
    this.isAnswerRevealed = false;
    this.capturedAnswer = false;
    this.capturedIndex = 0;
    this.timeodOutReveal = false;
  }

  handleProceedToNextQuestion = () => {
    clearTimeout(this.correctAnsTimeout);
    clearTimeout(this.incorrectAnsTimeout);

    //  if it's the last question
    if (this.currentSet >= this.totalSets - 1) {
      if (this.viewAnswers) {
        this.viewAnswers = false;
        this.isQuizCompleted = true;
      } else {
        this.isQuizCompleted = true;
      }
      return;
    }

    this.currentSet++;

    if (this.viewAnswers) {
      this.setViewAnswersState(this.currentSet); // Update for the next question
    } else if (this.answeredQuestions.has(this.currentSet) || this.revealedQuestions.has(this.currentSet)) {
      this.setAnsweredStateForCurrent();
    } else {
      const savedState = this.questionStates.get(this.currentSet);
      if (savedState) {
        this.isClicked = savedState.isClicked;
        this.capturedAnswer = savedState.capturedAnswer;
        this.capturedIndex = savedState.capturedIndex;
        this.wrongAttempts = savedState.wrongAttempts;
        this.timeodOutReveal = false;
        this.isAnswerRevealed = false;
      } else {
        this.resetQuizState();
      }
    }

    this.qnaset = [...this.qnaset];
  };

  handleViewAnswers = () => {
    this.currentSet = 0;
    this.viewAnswers = true;
    this.isQuizCompleted = false;
    this.setViewAnswersState(this.currentSet);
  };
  render() {
    return this.isInitial ? (
      <InitialCard
        quizTitle={this.quiztitle}
        quizDescription={this.fetchStatus.error ? 'Error occurred, please try again later!' : this.quizdescription}
        handleProceedQuiz={this.getQuizData}
        isLoading={this.fetchStatus.isLoading}
        btnTitle={this.fetchStatus.isLoading ? 'Loading' : this.fetchStatus.error ? 'Try again' : 'Take the quiz'}
      />
    ) : (
      <div class="quiz-parent__container">
        {this.isQuizCompleted ? (
          <ResultCard
            pyBtnTitle="Find care for sleep apnea"
            syBtnTitle="View correct answers"
            result={`You got ${this.score}/${this.totalSets}`}
            handleRevealAllAnswers={this.handleViewAnswers}
          />
        ) : (
          <QnACard
            structure={this.qnaset[this.currentSet]}
            clickHandle={this.handleOptionClick}
            isClicked={this.isClicked}
            capturedAnswer={this.capturedAnswer}
            handleRevealAnswer={this.handleRevealAnswer}
            capturedIndex={this.capturedIndex}
            handleProceedToNextQuestion={this.handleProceedToNextQuestion}
            isAnswerRevealed={{ isAnsRevealed: this.isAnswerRevealed, moreThanOneWrongAttempt: this.wrongAttempts >= 2, timeodOutReveal: this.timeodOutReveal }}
            status={`${this.currentSet + 1}/${this.totalSets}`}
            handleProceedQuiz={this.handleProceedQuiz}
            isMobile={this.isMobile}
          />
        )}
      </div>
    );
  }
}
