import { h } from '@stencil/core';
import { ResultCardProps } from '../types';

export const ResultCard = ({ pyBtnTitle, syBtnTitle, result, handleRevealAllAnswers }: ResultCardProps) => {
  return (
    <div class="parent-container initial-side-card d-flex final-card">
      <div class="d-flex flex-row justify-content-start gap-3" aria-labelledby="initial-label">
        <div class="parent-container-child">
          <div class="parent-container__content">
            <h2 class="parent-container_child__header mb-0">{result}</h2>
            <p class="parent-container_child__paragraph">
              Scroll to learn more about signs, symptoms, diagnosis, and treatment of sleep apnea.&nbsp; If you think you may be experiencing symptoms, talk to a provider now.
            </p>
          </div>
          <div class="parent-container_child__button">
            {/* button1 */}
            <button-component
              label={pyBtnTitle}
              onBtnClick={() => {
                window.location.href = 'https://lillydirect.lilly.com/sleep-apnea#take-action-section';
              }}
              btnId="find-care-for-sleep-apnea"
            >
              {pyBtnTitle}
            </button-component>
            <div class="osa-toast mt-2">
              {/* Buttton 2 */}
              <button-component label={syBtnTitle} onBtnClick={handleRevealAllAnswers} isbtnprimary="No" isArrow={false} btnId="view-correct-answers">
                {syBtnTitle}
              </button-component>
            </div>
          </div>
        </div>
        <div class="parent-container__right___column"></div>
      </div>
    </div>
  );
};
